    if panel.vertical != rimeAPI.get_option(session, "_vertical") {
      rimeAPI.set_option(session, "_vertical", panel.vertical)
    }
  }

  let handled = rimeAPI.process_key(session, Int32(rimeKeycode), Int32(rimeModifiers))

